-- T1: User-scoped composite primary keys for sync-domain tables.
--
-- Rationale: prior to this migration, every sync table used `id text primary key`
-- alongside a redundant `unique (id, owner_user_id)`. Because ids were unique
-- across the whole table, identical ids generated by two different users would
-- collide on conflict resolution, surfacing as "<entity> id <id> belongs to a
-- different owner" projection failures.
--
-- This migration recreates the eight user-scoped sync tables with a composite
-- primary key `(id, owner_user_id)` so each user owns their own keyspace, drops
-- the now-redundant id-only unique constraints, re-establishes child FKs against
-- the new composite PKs, and rewrites `sync_apply_projection_event` so that:
--   * every `on conflict (id)` becomes `on conflict (id, owner_user_id)`, and
--   * every "belongs to a different owner" exception branch is removed because
--     the cross-owner collision is impossible by construction.
--
-- The hosted DB will be wiped post-merge. `drop table cascade` is acceptable.
-- Sync metadata tables (`sync_device_ingest_state`, `sync_ingested_events`) are
-- left in place; their PKs already include `owner_user_id`.

-- -----------------------------------------------------------------------------
-- 1. Drop the eight sync entity tables (cascade removes FKs/policies/triggers
--    that depended on them; we recreate everything below).
-- -----------------------------------------------------------------------------

drop table if exists app_public.session_exercise_tags cascade;
drop table if exists app_public.exercise_tag_definitions cascade;
drop table if exists app_public.exercise_muscle_mappings cascade;
drop table if exists app_public.exercise_definitions cascade;
drop table if exists app_public.exercise_sets cascade;
drop table if exists app_public.session_exercises cascade;
drop table if exists app_public.sessions cascade;
drop table if exists app_public.gyms cascade;

-- -----------------------------------------------------------------------------
-- 2. Recreate tables with composite (id, owner_user_id) primary keys.
-- -----------------------------------------------------------------------------

create table app_public.gyms (
  id text not null,
  owner_user_id uuid not null default auth.uid() references auth.users (id) on delete cascade,
  name text not null check (length(btrim(name)) > 0),
  origin_scope_id text not null default 'private',
  origin_source_id text not null default 'local',
  deleted_at bigint check (deleted_at is null or deleted_at >= 0),
  created_at bigint not null check (created_at >= 0),
  updated_at bigint not null check (updated_at >= 0),
  primary key (id, owner_user_id)
);

create index gyms_owner_user_id_idx on app_public.gyms (owner_user_id);
create index gyms_name_idx on app_public.gyms (name);
create index gyms_origin_scope_id_idx on app_public.gyms (origin_scope_id);
create index gyms_deleted_at_idx on app_public.gyms (deleted_at);

create table app_public.sessions (
  id text not null,
  owner_user_id uuid not null default auth.uid() references auth.users (id) on delete cascade,
  gym_id text,
  status text not null default 'draft' check (status in ('draft', 'active', 'completed')),
  started_at bigint not null check (started_at >= 0),
  completed_at bigint check (completed_at is null or completed_at >= 0),
  duration_sec integer check (duration_sec is null or duration_sec >= 0),
  deleted_at bigint check (deleted_at is null or deleted_at >= 0),
  created_at bigint not null check (created_at >= 0),
  updated_at bigint not null check (updated_at >= 0),
  primary key (id, owner_user_id),
  constraint sessions_gym_owner_fk
    foreign key (gym_id, owner_user_id)
    references app_public.gyms (id, owner_user_id)
    on delete no action
);

create index sessions_owner_user_id_idx on app_public.sessions (owner_user_id);
create index sessions_status_idx on app_public.sessions (status);
create index sessions_completed_at_idx on app_public.sessions (completed_at);
create index sessions_deleted_at_idx on app_public.sessions (deleted_at);

create table app_public.exercise_definitions (
  id text not null,
  owner_user_id uuid not null default auth.uid() references auth.users (id) on delete cascade,
  name text not null check (length(btrim(name)) > 0),
  deleted_at bigint check (deleted_at is null or deleted_at >= 0),
  created_at bigint not null check (created_at >= 0),
  updated_at bigint not null check (updated_at >= 0),
  primary key (id, owner_user_id)
);

create index exercise_definitions_owner_user_id_idx
  on app_public.exercise_definitions (owner_user_id);
create index exercise_definitions_name_idx
  on app_public.exercise_definitions (name);
create index exercise_definitions_deleted_at_idx
  on app_public.exercise_definitions (deleted_at);

create table app_public.session_exercises (
  id text not null,
  owner_user_id uuid not null default auth.uid() references auth.users (id) on delete cascade,
  session_id text not null,
  exercise_definition_id text,
  order_index integer not null check (order_index >= 0),
  name text not null check (length(btrim(name)) > 0),
  machine_name text,
  origin_scope_id text not null default 'private',
  origin_source_id text not null default 'local',
  deleted_at bigint check (deleted_at is null or deleted_at >= 0),
  created_at bigint not null check (created_at >= 0),
  updated_at bigint not null check (updated_at >= 0),
  primary key (id, owner_user_id),
  constraint session_exercises_session_owner_fk
    foreign key (session_id, owner_user_id)
    references app_public.sessions (id, owner_user_id)
    on delete cascade
  -- NOTE: the historical exercise_definition_id FK was relaxed in
  -- 20260505213500_relax_session_exercise_definition_fk.sql so first-sync outbox
  -- events can land before the definition row arrives. We preserve that
  -- behaviour: exercise_definition_id is durable metadata, not a FK.
);

comment on column app_public.session_exercises.exercise_definition_id is
  'Durable exercise definition reference carried for history/sync metadata. The referenced definition may be seeded/local or arrive later via sync.';

create index session_exercises_owner_user_id_idx
  on app_public.session_exercises (owner_user_id);
create index session_exercises_session_id_idx
  on app_public.session_exercises (session_id);
create index session_exercises_exercise_definition_id_idx
  on app_public.session_exercises (exercise_definition_id);
create index session_exercises_deleted_at_idx
  on app_public.session_exercises (deleted_at);

create unique index session_exercises_session_order_active_unique
  on app_public.session_exercises (owner_user_id, session_id, order_index)
  where deleted_at is null;

create table app_public.exercise_sets (
  id text not null,
  owner_user_id uuid not null default auth.uid() references auth.users (id) on delete cascade,
  session_exercise_id text not null,
  order_index integer not null check (order_index >= 0),
  weight_value text not null default '',
  reps_value text not null default '',
  set_type text,
  deleted_at bigint check (deleted_at is null or deleted_at >= 0),
  created_at bigint not null check (created_at >= 0),
  updated_at bigint not null check (updated_at >= 0),
  primary key (id, owner_user_id),
  constraint exercise_sets_set_type_guard
    check (set_type is null or set_type in ('warm_up', 'rir_0', 'rir_1', 'rir_2')),
  constraint exercise_sets_session_exercise_owner_fk
    foreign key (session_exercise_id, owner_user_id)
    references app_public.session_exercises (id, owner_user_id)
    on delete cascade
);

create index exercise_sets_owner_user_id_idx
  on app_public.exercise_sets (owner_user_id);
create index exercise_sets_session_exercise_id_idx
  on app_public.exercise_sets (session_exercise_id);
create index exercise_sets_deleted_at_idx
  on app_public.exercise_sets (deleted_at);

create unique index exercise_sets_session_exercise_order_active_unique
  on app_public.exercise_sets (owner_user_id, session_exercise_id, order_index)
  where deleted_at is null;

create table app_public.exercise_muscle_mappings (
  id text not null,
  owner_user_id uuid not null default auth.uid() references auth.users (id) on delete cascade,
  exercise_definition_id text not null,
  muscle_group_id text not null check (length(btrim(muscle_group_id)) > 0),
  weight double precision not null check (weight > 0),
  role text check (role is null or role in ('primary', 'secondary', 'stabilizer')),
  created_at bigint not null check (created_at >= 0),
  updated_at bigint not null check (updated_at >= 0),
  primary key (id, owner_user_id),
  constraint exercise_muscle_mappings_exercise_muscle_owner_unique
    unique (exercise_definition_id, muscle_group_id, owner_user_id),
  constraint exercise_muscle_mappings_exercise_definition_owner_fk
    foreign key (exercise_definition_id, owner_user_id)
    references app_public.exercise_definitions (id, owner_user_id)
    on delete cascade
);

create index exercise_muscle_mappings_owner_user_id_idx
  on app_public.exercise_muscle_mappings (owner_user_id);
create index exercise_muscle_mappings_exercise_definition_id_idx
  on app_public.exercise_muscle_mappings (exercise_definition_id);
create index exercise_muscle_mappings_muscle_group_id_idx
  on app_public.exercise_muscle_mappings (muscle_group_id);

create table app_public.exercise_tag_definitions (
  id text not null,
  owner_user_id uuid not null default auth.uid() references auth.users (id) on delete cascade,
  exercise_definition_id text not null,
  name text not null check (length(btrim(name)) > 0),
  normalized_name text not null check (length(btrim(normalized_name)) > 0),
  deleted_at bigint check (deleted_at is null or deleted_at >= 0),
  created_at bigint not null check (created_at >= 0),
  updated_at bigint not null check (updated_at >= 0),
  primary key (id, owner_user_id),
  constraint exercise_tag_definitions_exercise_id_normalized_name_owner_unique
    unique (exercise_definition_id, normalized_name, owner_user_id),
  constraint exercise_tag_definitions_exercise_definition_owner_fk
    foreign key (exercise_definition_id, owner_user_id)
    references app_public.exercise_definitions (id, owner_user_id)
    on delete cascade
);

create index exercise_tag_definitions_owner_user_id_idx
  on app_public.exercise_tag_definitions (owner_user_id);
create index exercise_tag_definitions_exercise_definition_id_idx
  on app_public.exercise_tag_definitions (exercise_definition_id);
create index exercise_tag_definitions_deleted_at_idx
  on app_public.exercise_tag_definitions (deleted_at);

create table app_public.session_exercise_tags (
  id text not null,
  owner_user_id uuid not null default auth.uid() references auth.users (id) on delete cascade,
  session_exercise_id text not null,
  exercise_tag_definition_id text not null,
  created_at bigint not null check (created_at >= 0),
  primary key (id, owner_user_id),
  constraint session_exercise_tags_session_exercise_tag_owner_unique
    unique (session_exercise_id, exercise_tag_definition_id, owner_user_id),
  constraint session_exercise_tags_session_exercise_owner_fk
    foreign key (session_exercise_id, owner_user_id)
    references app_public.session_exercises (id, owner_user_id)
    on delete cascade,
  constraint session_exercise_tags_exercise_tag_definition_owner_fk
    foreign key (exercise_tag_definition_id, owner_user_id)
    references app_public.exercise_tag_definitions (id, owner_user_id)
    on delete cascade
);

create index session_exercise_tags_owner_user_id_idx
  on app_public.session_exercise_tags (owner_user_id);
create index session_exercise_tags_session_exercise_id_idx
  on app_public.session_exercise_tags (session_exercise_id);
create index session_exercise_tags_exercise_tag_definition_id_idx
  on app_public.session_exercise_tags (exercise_tag_definition_id);

