-- 7. Re-establish privilege grants on the rewritten projection function. The
--    `sync_events_ingest_impl` and `sync_events_ingest` wrappers continue to
--    work unchanged because they delegate via SQL invocation; their function
--    bodies do not embed table OIDs.
-- -----------------------------------------------------------------------------

revoke all on function app_public.sync_apply_projection_event(uuid, text, text, text, bigint, jsonb) from public;
grant execute on function app_public.sync_apply_projection_event(uuid, text, text, text, bigint, jsonb) to authenticated, service_role;

comment on function app_public.sync_apply_projection_event(uuid, text, text, text, bigint, jsonb) is
  'T1 rewrite: dispatch projection events using composite (id, owner_user_id) PK conflict resolution; cross-owner id collisions are impossible by construction.';
